namespace FinPatcher {
    [BepInPlugin(PluginInfo.ModGUID, PluginInfo.ModName, PluginInfo.ModVersion)]
    public class Plugin : BaseUnityPlugin {
        private readonly Harmony harmony = new Harmony(PluginInfo.ModGUID);
        private static Plugin Instance;

        public static ConfigEntry<bool> convertPounds;
        public static ConfigEntry<bool> clock24;
        public static ConfigEntry<bool> translateTerminal;

        private void Awake() {
            if (Instance == null) Instance = this;
            convertPounds = Config.Bind("Preference", "PoundsToKilograms", true, "Whether to convert pounds into kilograms. Values: [true | false].");
            clock24 = Config.Bind("Preference", "Clock24", true, "Whether to use a 24-hour clock format. Values: [true | false].");
            translateTerminal = Config.Bind("Preference", "TranslateTerminal", true, "Whether to translate the terminal as well. Values: [true | false].");

            if (convertPounds.Value) harmony.PatchAll(typeof(Patchers.WeightPatch));
            if (clock24.Value) harmony.PatchAll(typeof(Patchers.ClockPatch));
            if (translateTerminal.Value) {
                harmony.PatchAll(typeof(Patchers.TerminalNodePatch));
                harmony.PatchAll(typeof(Patchers.TerminalTextPatch));
            }
            Logger.LogInfo("FinPatcher initialized successfully.");
        }
    }

    public static class PluginInfo {
        public const string ModGUID = "com.acehanded.lethalcompany.finloc";
        public const string ModName = "FinPatcher";
        public const string ModVersion = "1.5.0";
    }
}

namespace Patchers {
    [HarmonyPatch(typeof(HUDManager), "Update")]
    internal class WeightPatch {
        [HarmonyPostfix]
        private static void Postfix(ref TextMeshProUGUI ___weightCounter) {
            int num = int.Parse(___weightCounter.text.Split()[0]);
            ___weightCounter.text = $"{Mathf.RoundToInt(num / 2.205f)} kg";
        }
    }

    [HarmonyPatch(typeof(HUDManager), "SetClock")]
    internal class ClockPatch {
        [HarmonyPostfix]
        private static void Postfix(float timeNormalized, float numberOfHours, ref TextMeshProUGUI ___clockNumber) {
            int num = (int)(timeNormalized * (60f * numberOfHours)) + 360;
            ___clockNumber.text = $"{num / 60:00}:{num % 60:00}";
        }
    }

    [HarmonyPatch(typeof(Terminal), "LoadNewNode")]
    internal class TerminalNodePatch {
        [HarmonyPrefix]
        private static void Prefix(ref TerminalNode node) {
            if (Dictionaries.Nodes.ContainsKey(node.name)) {
                node.displayText = Dictionaries.Nodes[node.name];
            }
        }
    }

    [HarmonyPatch(typeof(Terminal), "TextPostProcess")]
    internal class TerminalTextPatch {
        [HarmonyPrefix]
        private static void Prefix(ref string modifiedDisplayText) {
            List<string> list = new List<string>(7) {"Sunnuntai", "Maanantai", "Tiistai", "Keskiviikko", "Torstai", "Perjantai", "Lauantai"};
            modifiedDisplayText = modifiedDisplayText.Replace("[currentDay]", list[(int)DateTime.Now.DayOfWeek]);
        }

        [HarmonyPostfix]
        private static void Postfix(ref string __result) {
            foreach (KeyValuePair<string, string> item in Dictionaries.TextPostProcess) {
                __result = Regex.Replace(__result, item.Key, item.Value);
            }
        }
    }
}
